import android.util.Log
import timber.log.Timber
import java.util.concurrent.ConcurrentHashMap

object SecureLogger {
    private val TAG = "SecureLogger"
    private val sensitiveFields = setOf(
        "password", "token", "secret", "credential", "auth", "key", "pin", "code"
    )
    private val redactedValues = mutableMapOf<String, String>()
    
    fun init() {
        if (BuildConfig.DEBUG) {
            Timber.plant(Timber.DebugTree())
        } else {
            Timber.plant(object : Timber.Tree() {
                override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
                    // Production logging - only critical errors
                    if (priority >= Log.ERROR) {
                        Log.println(priority, tag ?: TAG, message)
                        t?.let { Log.println(priority, tag ?: TAG, Log.getStackTraceString(it)) }
                    }
                }
            })
        }
    }
    
    fun logAuthAttempt(userId: String?, success: Boolean, method: String) {
        val userIdToLog = if (userId.isNullOrEmpty()) "ANONYMOUS" else "USER_$userId"
        val logMessage = "AUTH: $method - ${if (success) "SUCCESS" else "FAILED"} for $userIdToLog"
        Timber.tag("AUTH").i(logMessage)
    }
    
    fun logDatabaseQuery(query: String, params: Map<String, Any?>) {
        val redactedQuery = redactQuery(query)
        val redactedParams = redactParams(params)
        Timber.tag("DB").v("QUERY: $redactedQuery | PARAMS: $redactedParams")
    }
    
    fun logApiRequest(url: String, method: String, headers: Map<String, String>, body: String?) {
        val redactedHeaders = redactHeaders(headers)
        val redactedBody = body?.let { redactBody(it) } ?: "NO_BODY"
        Timber.tag("API").v("REQ: $method $url | HEADERS: $redactedHeaders | BODY: $redactedBody")
    }
    
    fun logApiResponse(url: String, statusCode: Int, headers: Map<String, String>, body: String?) {
        val redactedHeaders = redactHeaders(headers)
        val redactedBody = body?.let { redactBody(it) } ?: "NO_BODY"
        Timber.tag("API").v("RESP: $url | STATUS: $statusCode | HEADERS: $redactedHeaders | BODY: $redactedBody")
    }
    
    fun logException(exception: Throwable, context: String = "") {
        Timber.tag("EXCEPTION").e(exception, "CONTEXT: $context")
    }
    
    private fun redactQuery(query: String): String {
        return query.replace(Regex("SELECT.*?FROM|INSERT.*?INTO|UPDATE.*?SET|DELETE.*?FROM"), "REDACTED_QUERY")
    }
    
    private fun redactParams(params: Map<String, Any?>): Map<String, Any?> {
        return params.mapValues { entry ->
            if (entry.key.lowercase() in sensitiveFields) {
                "REDACTED"
            } else {
                entry.value
            }
        }
    }
    
    private fun redactHeaders(headers: Map<String, String>): Map<String, String> {
        return headers.mapValues { entry ->
            if (entry.key.lowercase() in listOf("authorization", "cookie", "x-api-key")) {
                "REDACTED"
            } else {
                entry.value
            }
        }
    }
    
    private fun redactBody(body: String): String {
        return try {
            val jsonObject = org.json.JSONObject(body)
            val redactedObject = org.json.JSONObject()
            val keys = jsonObject.keys()
            
            while (keys.hasNext()) {
                val key = keys.next()
                if (key.lowercase() in sensitiveFields) {
                    redactedObject.put(key, "REDACTED")
                } else {
                    redactedObject.put(key, jsonObject.get(key))
                }
            }
            redactedObject.toString()
        } catch (e: Exception) {
