class SecureLoggingInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val startTime = System.currentTimeMillis()
        
        try {
            SecureLogger.logApiRequest(
                url = request.url.toString(),
                method = request.method,
                headers = request.headers.associateWith { it },
                body = request.body?.let { 
                    val buffer = Buffer()
                    it.writeTo(buffer)
                    buffer.readUtf8()
                }
            )
            
            val response = chain.proceed(request)
            
            val responseBody = response.body?.let { 
                val buffer = Buffer()
                it.source().readAll(buffer)
                buffer.readUtf8()
            }
            
            SecureLogger.logApiResponse(
                url = response.request.url.toString(),
                statusCode = response.code,
                headers = response.headers.associateWith { it },
                body = responseBody
            )
            
            return response
        } catch (e: Exception) {
            SecureLogger.logException(e, "API_INTERCEPTOR_ERROR")
            throw e
        }
    }
}

